# Configuration for the insurance service WSDL
WSDL_URL = "https://insurance-service.example.com/PolicyService?wsdl"


def validate_policy_number(policy_number: str) -> str:
    """Validate and sanitize policy number input.
    
    Policy numbers should match a specific format (alphanumeric with optional dashes).
    This prevents injection of XML/SOAP special characters.
    """
    if not policy_number:
        raise ValueError("Policy number cannot be empty")
    
    # Allow only alphanumeric characters, dashes, and underscores
    pattern = r'^[A-Za-z0-9\-_]{1,50}$'
    if not re.match(pattern, policy_number):
        raise ValueError(
            "Invalid policy number format. Only alphanumeric characters, "
            "dashes, and underscores are allowed (max 50 characters)."
        )
    
    return policy_number.strip()


def validate_customer_name(customer_name: str) -> str:
    """Validate and sanitize customer name input.
    
    Customer names should contain only letters, spaces, hyphens, and apostrophes.
    This prevents injection of XML/SOAP special characters.
    """
    if not customer_name:
        raise ValueError("Customer name cannot be empty")
    
    if len(customer_name) > 200:
        raise ValueError("Customer name must be 200 characters or fewer")
    
    # Allow only letters (including unicode letters), spaces, hyphens, apostrophes, and periods
    pattern = r"^[\w\s\-'.]+$"
    if not re.match(pattern, customer_name, re.UNICODE):
        raise ValueError(
            "Invalid customer name. Only letters, spaces, hyphens, "
            "apostrophes, and periods are allowed."
        )
    
    return customer_name.strip()


def xml_escape(value: str) -> str:
    """Escape XML special characters as an additional defense-in-depth measure.
    
    Even though zeep handles parameterized SOAP message construction,
    this provides an extra layer of protection.
    """
    # Use lxml's built-in escaping
    escaped = (
        value
        .replace("&", "&amp;")
        .replace("<", "&lt;")
        .replace(">", "&gt;")
        .replace('"', "&quot;")
        .replace("'", "&apos;")
    )
    return escaped


def create_soap_client(wsdl_url: str) -> Client:
    """Create a zeep SOAP client with secure settings."""
    from zeep.transports import Transport
    from requests import Session
    
    session = Session()
    # Set reasonable timeouts to prevent hanging
    transport = Transport(session=session, timeout=30, operation_timeout=30)
    
    # Disable XML entity expansion to prevent XXE attacks
    from lxml import etree
    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True,
        dtd_validation=False,
        load_dtd=False,
    )
    
    # Create client with strict mode to validate against schema
    client = Client(
        wsdl_url,
        transport=transport,
        strict=True,
    )
    
    # Configure the XML parser on the transport to prevent XXE
    client.transport.session.headers.update({
        'Content-Type': 'text/xml; charset=utf-8',
    })
    
    return client


def lookup_policy(policy_number: str, customer_name: str) -> dict:
    """Look up an insurance policy using the SOAP service.
    
    Uses zeep's parameterized approach to construct SOAP messages safely.
    Zeep builds the XML programmatically from Python objects, which inherently
    prevents SOAP XML injection because values are treated as data, not markup.
    
    Args:
        policy_number: The policy number to look up
        customer_name: The customer name associated with the policy
        
    Returns:
        Dictionary containing policy information
    """
    # Step 1: Validate inputs with strict allowlists
    validated_policy = validate_policy_number(policy_number)
    validated_name = validate_customer_name(customer_name)
    
    try:
        client = create_soap_client(WSDL_URL)
        
        # Step 2: Use zeep's parameterized API to pass values safely.
        # Zeep constructs the SOAP XML body using its type system,
        # which means user input is serialized as text content within
        # XML elements — NOT concatenated into raw XML strings.
        # This is the SOAP equivalent of parameterized queries.
        response = client.service.LookupPolicy(
            PolicyNumber=validated_policy,
            CustomerName=validated_name,
        )
        
        # Step 3: Process the response
        result = {
            "status": "success",
            "policy_number": validated_policy,
            "customer_name": validated_name,
            "response": response,
        }
        
        return result
        
    except Fault as e:
        return {
            "status": "soap_fault",
            "error": str(e.message) if hasattr(e, 'message') else str(e),
            "code": str(e.code) if hasattr(e, 'code') else "UNKNOWN",
        }
    except TransportError as e:
        return {
            "status": "transport_error",
            "error": f"Communication error with insurance service: {e}",
        }
    except Exception as e:
        return {
            "status": "error",
            "error": f"Unexpected error: {type(e).__name__}",
        }


